const r = $input.first().json;
const lines = [];
lines.push('🏢 Commercial Stack Engine — Daily Digest');
lines.push(`📅 ${new Date().toLocaleDateString('en-US',{timeZone:'America/Phoenix'})}`);
lines.push('');
lines.push(`🔥 HOT leads (24h): ${r.hot_count}`);
lines.push(`💧 WARM leads (24h): ${r.warm_count}`);
lines.push(`📥 Scraped: ${r.scraped_count}`);
lines.push(`💵 Claude spend (24h): $${Number(r.claude_cost_24h || 0).toFixed(3)}`);
lines.push(`⚠️ Errors: ${r.errors_count}`);
if (r.top_hot && r.top_hot.length) {
  lines.push('');
  lines.push('Top 5 HOT leads:');
  for (const l of r.top_hot) {
    lines.push(`  • ${l.overall_score}/100 — ${l.address || '(no street)'} ${l.city}, ${l.state} — ${l.asset_class.toUpperCase()} ${l.units || '?'}u — $${(l.listing_price || 0).toLocaleString()} — ${l.equity_estimate_percent}% eq — ${l.recommended_structure?.type || 'n/a'}`);
  }
}
return [{ json: { text: lines.join('\n'), ...r } }];
